CREATE INDEX idx_work_member              ON tbl_work_history (icai_membership_no);

-- ============================================================================
-- SECTION 3 — FOREIGN KEYS
-- ============================================================================

ALTER TABLE tbl_app_user ADD CONSTRAINT fk_app_user_created_by FOREIGN KEY (created_by) REFERENCES tbl_app_user (user_id) ON DELETE CASCADE ON UPDATE CASCADE;
ALTER TABLE tbl_app_user ADD CONSTRAINT fk_app_user_updated_by FOREIGN KEY (updated_by) REFERENCES tbl_app_user (user_id) ON DELETE CASCADE ON UPDATE CASCADE;

ALTER TABLE tbl_org_details ADD CONSTRAINT fk_org_created_by FOREIGN KEY (created_by) REFERENCES tbl_app_user (user_id) ON DELETE CASCADE ON UPDATE CASCADE;
