-- ============================================================================
-- SECTION 4 — updated_at TRIGGERS (replaces MySQL's ON UPDATE CURRENT_TIMESTAMP)
--  21 of the 26 tables have it; tbl_ca_member_fact, tbl_campaign_goal,
--  tbl_user_universe, tbl_app_user(*) -- wait, app_user IS in the list, see below.
--  Applied to exactly the tables confirmed (via information_schema) to have
--  ON UPDATE CURRENT_TIMESTAMP on updated_at in the live MySQL schema.
-- ============================================================================

CREATE OR REPLACE FUNCTION set_updated_at() RETURNS trigger AS $$
BEGIN
  NEW.updated_at = CURRENT_TIMESTAMP;
  RETURN NEW;
END;
$$ LANGUAGE plpgsql;

CREATE TRIGGER trg_upd_tbl_activity                      BEFORE UPDATE ON tbl_activity                      FOR EACH ROW EXECUTE FUNCTION set_updated_at();
CREATE TRIGGER trg_upd_tbl_activity_participant           BEFORE UPDATE ON tbl_activity_participant           FOR EACH ROW EXECUTE FUNCTION set_updated_at();
